// ---- shared helpers --------------------------------------------------------
function gNearestN(world, x, y, n, maxD = 250) {   // 原#5: shorter range + line-of-sight
  const r = [];
  for (const e of world.enemies) { if (e.dead || e.spawnT > 0) continue; const d = dist2(x, y, e.x, e.y); if (d < maxD * maxD && world.lineClear(x, y, e.x, e.y)) r.push([d, e]); }
  r.sort((a, b) => a[0] - b[0]);
  return r.slice(0, n).map((q) => q[1]);
}
function gRoll(p, base) {
  const crit = Math.random() < (p.stats.critChance || 0);
  return { dmg: base * (p.stats.damageMult || 1) * (crit ? (p.stats.critMult || 2) : 1) * (0.92 + Math.random() * 0.16), crit };
}
const gFaceA = (p) => Math.atan2(p.faceY || 0, p.faceX || 1);

// ===========================================================================
// 1) 散魂霰彈 — shotgun spread of soul pellets toward the nearest enemy.
//    Evolves into 散魂風暴砲 when owning the "multishot" passive.
// ===========================================================================
Weapons.register({
  id: 'g_scatter', name: '散魂霰彈', icon: 'weapon_g_scatter', tier: 1, weight: 8, maxLevel: 8,
  cooldown: (l) => Math.max(0.5, 1.0 - l * 0.05),
  fire(world, p, inst) {
    const l = inst.level;
    const pellets = 4 + l + (p.stats.projCountAdd || 0);
    const spread = 0.62;
    const tgt = gNearestN(world, p.x, p.y, 1)[0];
    const base = tgt ? Math.atan2(tgt.y - p.y, tgt.x - p.x) : gFaceA(p);
    const sp = 210 * (p.stats.projSpeedMult || 1);
    for (let i = 0; i < pellets; i++) {
      const a = base + (pellets > 1 ? (i / (pellets - 1) - 0.5) * spread : 0) + (Math.random() - 0.5) * 0.08;
      const { dmg, crit } = gRoll(p, 6 + l * 2.1);
      world.addProjectile(new Projectile({ x: p.x, y: p.y, vx: Math.cos(a) * sp, vy: Math.sin(a) * sp, damage: dmg, crit, faction: 'player', sprite: 'g_fx_pellet', color: P.emberL, radius: 2.4, pierce: Math.floor(l / 5) + (p.stats.pierceAdd || 0), knockback: 22, life: 0.5 }));
    }
    world.particles.burst(p.x, p.y, 5, { angle: base, spread: 0.5, speed: 90, color: [P.emberL, P.white], size: 1.6, life: 0.16, glow: true });
    Sfx.play('shoot');
  },
  levelDesc: (l) => `彈丸 ${4 + l}・單發 ${(6 + l * 2.1) | 0}・穿透 ${Math.floor(l / 5)}`,
  desc: '朝最近敵人噴出一束碎魂彈丸，貼臉傷害爆發。',
  evolveInto: 'g_scatter_evo', evolveReq: 'multishot',
});

// ===========================================================================
// 2) 回力晶刃 — boomerang blades that fly out and curve back through enemies.
//    Custom blade entities tracked in inst.st (true out-and-back motion).
// ===========================================================================
Weapons.register({
  id: 'g_boomer', name: '回力晶刃', icon: 'weapon_g_boomer', tier: 2, weight: 7, maxLevel: 6,
  cooldown: (l) => Math.max(0.7, 1.4 - l * 0.1),
  fire(world, p, inst) {
    const l = inst.level;
    const count = 1 + Math.floor((l + 1) / 2);
    const reach = (78 + l * 12) * (p.stats.area || 1);
    const tgt = gNearestN(world, p.x, p.y, 1)[0];
    const base = tgt ? Math.atan2(tgt.y - p.y, tgt.x - p.x) : gFaceA(p);
    inst.st.blades = inst.st.blades || [];
    for (let i = 0; i < count; i++) {
      const a = base + (count > 1 ? (i / (count - 1) - 0.5) * 0.5 : 0);
      const { dmg } = gRoll(p, 11 + l * 4);
      inst.st.blades.push({ x: p.x, y: p.y, a, t: 0, reach, dmg, dur: 1.0, hits: new Map(), spin: 0 });
    }
    Sfx.play('shoot');
  },
  update(world, p, inst, dt) {
    const blades = inst.st.blades; if (!blades || !blades.length) return;
    for (let i = blades.length - 1; i >= 0; i--) {
      const b = blades[i];
      b.t += dt; b.spin += dt * 18;
      const k = Math.min(1, b.t / b.dur);
      // out then back: sine ramp 0->1->0; also home back toward the (moving) player on return
      const departed = reachEase(k) * b.reach;
      if (k > 0.5) { // returning: aim toward player so it follows you home
        const back = Math.atan2(p.y - b.y, p.x - b.x);
        b.a = lerpAngle(b.a, back, dt * 3.2);
      }
      b.x = p.x + Math.cos(b.a) * departed;
      b.y = p.y + Math.sin(b.a) * departed;
      const R = 9;
      for (const e of world.enemies) {
        if (e.dead || e.spawnT > 0) continue;
        if (dist2(b.x, b.y, e.x, e.y) < (e.radius + R) * (e.radius + R)) {
          const last = b.hits.get(e) || 0;
          if (world.time > last) {
            b.hits.set(e, world.time + 0.28);
            const crit = Math.random() < (p.stats.critChance || 0);
            const d = b.dmg * (crit ? (p.stats.critMult || 2) : 1);
            const kb = 24 * (p.stats.knockbackMult || 1);
            e.hurt(d, Math.cos(b.a) * kb, Math.sin(b.a) * kb, world, crit);
          }
        }
      }
      if (b.t >= b.dur) blades.splice(i, 1);
    }
  },
  draw(world, p, inst) {
    const blades = inst.st.blades; if (!blades) return;
    const sp = getSprite('g_fx_chakram');
    for (const b of blades) {
      glowWorld(b.x, b.y, 7, P.shardL, 0.4);
      drawSprite(sp.frames[0], b.x, b.y, { ax: sp.ax, ay: sp.ay, rot: b.spin });
    }
  },
  desc: '擲出回力晶刃飛出再折返，沿途反覆切削敵人。',
});

// ===========================================================================
// 3) 魂能地雷 — drops armed mines that detonate when an enemy steps close.
//    Mines tracked in inst.st; old mines expire so the field never piles up.
// ===========================================================================
Weapons.register({
  id: 'g_mine', name: '魂能地雷', icon: 'weapon_g_mine', tier: 2, weight: 7, maxLevel: 6,
  cooldown: (l) => Math.max(0.6, 1.3 - l * 0.09),
  fire(world, p, inst) {
    const l = inst.level;
    inst.st.mines = inst.st.mines || [];
    const cap = 4 + l;
    // scatter the mine a little behind/around the player
    const ang = gFaceA(p) + Math.PI + (Math.random() - 0.5) * 1.4;
    const off = 6 + Math.random() * 16;
    const mx = p.x + Math.cos(ang) * off, my = p.y + Math.sin(ang) * off;
    inst.st.mines.push({ x: mx, y: my, arm: 0.4, life: 8, blast: (40 + l * 6) * (p.stats.area || 1), dmg: 18 + l * 8, pulse: Math.random() * TAU });
    while (inst.st.mines.length > cap) inst.st.mines.shift();
  },
  update(world, p, inst, dt) {
    const mines = inst.st.mines; if (!mines || !mines.length) return;
    for (let i = mines.length - 1; i >= 0; i--) {
      const m = mines[i];
      m.arm -= dt; m.life -= dt; m.pulse += dt * 6;
      let trigger = m.life <= 0;
      if (m.arm <= 0 && !trigger) {
        const sense = 16;
        for (const e of world.enemies) {
          if (e.dead || e.spawnT > 0) continue;
          if (dist2(m.x, m.y, e.x, e.y) < (e.radius + sense) * (e.radius + sense)) { trigger = true; break; }
        }
      }
      if (trigger) {
        const crit = Math.random() < (p.stats.critChance || 0);
        const d = m.dmg * (p.stats.damageMult || 1) * (crit ? (p.stats.critMult || 2) : 1);
        world.spawnExplosion(m.x, m.y, m.blast, P.ember, d, { knockback: 120 * (p.stats.knockbackMult || 1) });
        mines.splice(i, 1);
      }
    }
  },
  draw(world, p, inst) {
    const mines = inst.st.mines; if (!mines) return;
    const sp = getSprite('g_fx_mine');
    for (const m of mines) {
      const armed = m.arm <= 0;
      const blink = armed ? (0.4 + 0.4 * (0.5 + 0.5 * Math.sin(m.pulse))) : 0.2;
      glowWorld(m.x, m.y, 5, armed ? P.red : P.emberL, blink);
      drawSprite(sp.frames[0], m.x, m.y, { ax: sp.ax, ay: sp.ay });
    }
  },
  levelDesc: (l) => `同時 ${4 + l} 雷・爆傷 ${(18 + l * 8) | 0}`,
  desc: '佈下感應地雷，敵人靠近即引爆造成範圍重創。',
});

