// ===========================================================================
// 5) 劇毒霧域 — a lingering poison cloud around the player (domain weapon).
//    Persistent update+draw; ticks area damage on a fixed cadence.
// ===========================================================================
Weapons.register({
  id: 'g_venomfog', name: '劇毒霧域', icon: 'weapon_g_venomfog', tier: 2, weight: 6, maxLevel: 6,
  update(world, p, inst, dt) {
    const l = inst.level;
    const R = (40 + l * 7) * (p.stats.area || 1);
    inst.st.r = R;
    inst.st.tick = (inst.st.tick || 0) - dt;
    if (inst.st.tick <= 0) {
      inst.st.tick = 0.45;
      const { dmg } = gRoll(p, 4 + l * 1.8);
      world.dealAreaDamage(p.x, p.y, R, dmg, { knockback: 0 });
    }
  },
  draw(world, p, inst) {
    const R = inst.st.r || 40;
    fillCircleWorld(p.x, p.y, R, withAlpha(P.poisonD, 0.10));
    fillCircleWorld(p.x, p.y, R * 0.66, withAlpha(P.poison, 0.07));
    if (Math.random() < 0.6) {
      const a = Math.random() * TAU, rr = Math.random() * R;
      world.particles.spawn({ x: p.x + Math.cos(a) * rr, y: p.y + Math.sin(a) * rr, life: 0.5, size: 2.2, color: Math.random() < 0.5 ? P.poison : P.toxic, glow: true, drag: 0.92, grav: -12 });
    }
  },
  levelDesc: (l) => `半徑 ${(40 + l * 7) | 0}・每跳 ${(4 + l * 1.8) | 0}`,
  desc: '在腳下瀰漫劇毒霧氣，持續腐蝕範圍內所有敵人。',
});

// ===========================================================================
// 6) 寒冰錐 — fires piercing ice spears at nearest foes with heavy knockback.
// ===========================================================================
Weapons.register({
  id: 'g_icespear', name: '寒冰錐', icon: 'weapon_g_icespear', tier: 1, weight: 8, maxLevel: 8,
  cooldown: (l) => Math.max(0.45, 0.95 - l * 0.06),
  fire(world, p, inst) {
    const l = inst.level;
    const count = 1 + Math.floor(l / 2) + (p.stats.projCountAdd || 0);
    const targets = gNearestN(world, p.x, p.y, count);
    if (!targets.length) return;
    const sp = 250 * (p.stats.projSpeedMult || 1);
    for (let i = 0; i < count; i++) {
      const t = targets[i % targets.length];
      const a = Math.atan2(t.y - p.y, t.x - p.x) + (Math.random() - 0.5) * 0.05;
      const { dmg, crit } = gRoll(p, 8 + l * 3.2);
      world.addProjectile(new Projectile({ x: p.x, y: p.y, vx: Math.cos(a) * sp, vy: Math.sin(a) * sp, damage: dmg, crit, faction: 'player', sprite: 'g_fx_icespear', color: P.ice, radius: 3, pierce: 1 + Math.floor(l / 3) + (p.stats.pierceAdd || 0), knockback: 46 * (p.stats.knockbackMult || 1), life: 1.2, scale: 1.05 }));
    }
    Sfx.play('shoot');
  },
  levelDesc: (l) => `冰錐 ${1 + Math.floor(l / 2)}・傷害 ${(8 + l * 3.2) | 0}・穿透 ${1 + Math.floor(l / 3)}`,
  desc: '射出貫穿的寒冰錐，命中強力擊退凍緩敵勢。',
});

